import{_ as i,c as a,o as e,aj as r}from"./chunks/framework.CynFBi0q.js";const g=JSON.parse('{"title":"Go 实战训练营 - 知识结构目录","description":"","frontmatter":{},"headers":[],"relativePath":"handbook/go-practice/index.md","filePath":"handbook/go-practice/index.md","lastUpdated":0}'),o={name:"handbook/go-practice/index.md"};function n(t,l,h,s,d,c){return e(),a("div",null,[...l[0]||(l[0]=[r('<h1 id="go-实战训练营-知识结构目录" tabindex="-1">Go 实战训练营 - 知识结构目录 <a class="header-anchor" href="#go-实战训练营-知识结构目录" aria-label="Permalink to “Go 实战训练营 - 知识结构目录”">​</a></h1><h2 id="课程概览" tabindex="-1">课程概览 <a class="header-anchor" href="#课程概览" aria-label="Permalink to “课程概览”">​</a></h2><h3 id="课程定位" tabindex="-1">课程定位 <a class="header-anchor" href="#课程定位" aria-label="Permalink to “课程定位”">​</a></h3><p>针对 1-3 年初级 Go 开发工程师，系统提升实战能力，达到字节 2-1 水平</p><h3 id="核心特色" tabindex="-1">核心特色 <a class="header-anchor" href="#核心特色" aria-label="Permalink to “核心特色”">​</a></h3><ul><li><strong>大厂能力模型导向</strong>：直击开源框架及中间件底层核心原理</li><li><strong>实战驱动</strong>：手写 Web 框架、ORM 框架、缓存组件、微服务框架</li><li><strong>源码级教学</strong>：深入 Gin、Beego、Echo、Kratos 等主流框架实现</li><li><strong>面试导向</strong>：每个模块配备面试要点和常见问题</li></ul><h3 id="课程结构" tabindex="-1">课程结构 <a class="header-anchor" href="#课程结构" aria-label="Permalink to “课程结构”">​</a></h3><table tabindex="0"><thead><tr><th>维度</th><th>内容</th></tr></thead><tbody><tr><td>周期</td><td>15周</td></tr><tr><td>模块</td><td>8大内容模块</td></tr><tr><td>实战</td><td>4大实战案例</td></tr><tr><td>加餐</td><td>4个热门面试主题</td></tr><tr><td>代码</td><td>完整代码仓库</td></tr></tbody></table><hr><h2 id="模块一-web-框架-3周" tabindex="-1">模块一：Web 框架（3周） <a class="header-anchor" href="#模块一-web-框架-3周" aria-label="Permalink to “模块一：Web 框架（3周）”">​</a></h2><h3 id="教学目标" tabindex="-1">教学目标 <a class="header-anchor" href="#教学目标" aria-label="Permalink to “教学目标”">​</a></h3><ol><li>掌握 Web 框架的基本原理</li><li>掌握如何设计并实现一棵前缀路由树，支持通配符匹配、路径参数</li><li>掌握 HTTP Server 和 Context 的设计，并且提供丰富 API</li><li>掌握 HTTP 中 Session 的设计和实现</li><li>掌握 Web 框架中 AOP 的解决方案</li><li>设计并实现简单的静态资源服务器</li></ol><h3 id="学习痛点" tabindex="-1">学习痛点 <a class="header-anchor" href="#学习痛点" aria-label="Permalink to “学习痛点”">​</a></h3><ul><li>用过很多 Web 框架，但不了解原理，不知道怎么注册路由、执行路由匹配</li><li>面试时无法清晰阐述前缀路由树的原理，不知道如何快速定位 404 错误</li><li>不知道如何设计统一的 Session 抽象，支持本地内存或 Redis</li><li>无法灵活运用 AOP 方案解决登录校验、鉴权、日志、tracing、logging 等问题</li></ul><h3 id="第一周-web-框架核心设计" tabindex="-1">第一周：Web 框架核心设计 <a class="header-anchor" href="#第一周-web-框架核心设计" aria-label="Permalink to “第一周：Web 框架核心设计”">​</a></h3><h4 id="_1-1-web-框架概览与核心设计" tabindex="-1">1.1 Web 框架概览与核心设计 <a class="header-anchor" href="#_1-1-web-框架概览与核心设计" aria-label="Permalink to “1.1 Web 框架概览与核心设计”">​</a></h4><ul><li>Web 框架架构演进：从标准库到框架化</li><li>核心组件：Server、Context、路由树</li><li>开源实例分析：Gin、Beego 中的 Server 和 Context 抽象</li></ul><h4 id="_1-2-http-包进阶语法" tabindex="-1">1.2 HTTP 包进阶语法 <a class="header-anchor" href="#_1-2-http-包进阶语法" aria-label="Permalink to “1.2 HTTP 包进阶语法”">​</a></h4><ul><li><code>net/http</code> 包核心原理</li><li>Handler 接口设计与实现</li><li>代码演示：Web 框架与 HTTP 包的结合点</li></ul><h4 id="_1-3-前缀路由树设计与实现" tabindex="-1">1.3 前缀路由树设计与实现 <a class="header-anchor" href="#_1-3-前缀路由树设计与实现" aria-label="Permalink to “1.3 前缀路由树设计与实现”">​</a></h4><ul><li><strong>开源实例</strong>：HttpRouter、Gin、Beego、Echo、Iris 路由树设计对比</li><li><strong>核心原理</strong>：前缀树（Trie）数据结构</li><li><strong>设计实现</strong>： <ul><li>路由节点结构设计</li><li>通配符匹配实现（<code>*</code> 通配）</li><li>路径参数提取（<code>:param</code> 语法）</li></ul></li><li><strong>代码演示</strong>：实现前缀路由树，支持通配符匹配和路径参数</li><li><strong>作业</strong>：支持正则匹配路由</li><li><strong>面试要点</strong>：路由匹配算法复杂度分析</li></ul><h3 id="第二周-aop-方案设计" tabindex="-1">第二周：AOP 方案设计 <a class="header-anchor" href="#第二周-aop-方案设计" aria-label="Permalink to “第二周：AOP 方案设计”">​</a></h3><h4 id="_2-1-aop-设计模式详解" tabindex="-1">2.1 AOP 设计模式详解 <a class="header-anchor" href="#_2-1-aop-设计模式详解" aria-label="Permalink to “2.1 AOP 设计模式详解”">​</a></h4><ul><li><strong>责任链模式</strong>（Chain of Responsibility）</li><li><strong>洋葱模式</strong>（Onion Model）</li><li><strong>拦截器</strong>（Interceptor）机制</li></ul><h4 id="_2-2-开源框架-aop-实现对比" tabindex="-1">2.2 开源框架 AOP 实现对比 <a class="header-anchor" href="#_2-2-开源框架-aop-实现对比" aria-label="Permalink to “2.2 开源框架 AOP 实现对比”">​</a></h4><ul><li><strong>Gin</strong>：Handler 链设计与实现</li><li><strong>Beego</strong>：Filter 过滤器设计</li><li><strong>Kratos</strong>：Middleware 中间件设计</li></ul><h4 id="_2-3-代码演示-为-web-框架提供-aop-支持" tabindex="-1">2.3 代码演示：为 Web 框架提供 AOP 支持 <a class="header-anchor" href="#_2-3-代码演示-为-web-框架提供-aop-支持" aria-label="Permalink to “2.3 代码演示：为 Web 框架提供 AOP 支持”">​</a></h4><ul><li>Access Log（访问日志）中间件</li><li>Tracing（链路追踪）中间件</li><li>Metric（指标监控）中间件</li><li>Recovery：从 panic 中恢复</li><li>错误处理：返回特定错误页面或重定向</li><li><strong>面试要点</strong>：中间件执行顺序、panic 恢复机制</li></ul><h3 id="第三周-高级功能实现" tabindex="-1">第三周：高级功能实现 <a class="header-anchor" href="#第三周-高级功能实现" aria-label="Permalink to “第三周：高级功能实现”">​</a></h3><h4 id="_3-1-文件上传与下载" tabindex="-1">3.1 文件上传与下载 <a class="header-anchor" href="#_3-1-文件上传与下载" aria-label="Permalink to “3.1 文件上传与下载”">​</a></h4><ul><li><strong>开源实例</strong>：Gin、Beego、Iris、Echo 文件处理对比</li><li>文件上传：multipart/form-data 解析</li><li>文件下载：Content-Disposition 处理</li><li><strong>进阶语法</strong>：Go 文件操作 API</li><li><strong>代码演示</strong>：实现文件上传下载功能</li></ul><h4 id="_3-2-页面渲染与模板引擎" tabindex="-1">3.2 页面渲染与模板引擎 <a class="header-anchor" href="#_3-2-页面渲染与模板引擎" aria-label="Permalink to “3.2 页面渲染与模板引擎”">​</a></h4><ul><li>模板引擎设计原理</li><li><strong>进阶语法</strong>：Go <code>text/template</code> 与 <code>html/template</code></li><li><strong>代码演示</strong>：在 Web 框架中支持页面渲染</li><li><strong>设计模式</strong>：Option 模式（函数式选项）</li><li><strong>代码演示</strong>：使用泛型设计通用的 Option 模式</li></ul><h4 id="_3-3-静态资源支持" tabindex="-1">3.3 静态资源支持 <a class="header-anchor" href="#_3-3-静态资源支持" aria-label="Permalink to “3.3 静态资源支持”">​</a></h4><ul><li><strong>开源实例</strong>：各框架静态资源处理对比</li><li><strong>代码演示</strong>：设计可配置、可扩展的静态资源处理器 <ul><li>缓存静态资源（内存缓存策略）</li><li>控制缓存消耗（LRU 淘汰）</li><li>大文件解决方案（分块传输）</li></ul></li></ul><h4 id="_3-4-session-设计与实现" tabindex="-1">3.4 Session 设计与实现 <a class="header-anchor" href="#_3-4-session-设计与实现" aria-label="Permalink to “3.4 Session 设计与实现”">​</a></h4><ul><li><strong>开源实例</strong>：Beego Session 模块、Gin Session 扩展</li><li><strong>代码演示</strong>：Session API 设计与实现 <ul><li>基于内存的实现</li><li>基于 Redis 的实现</li></ul></li><li><strong>面试要点</strong>：Session 与 Cookie 区别、分布式 Session 方案</li></ul><h3 id="模块一实战项目" tabindex="-1">模块一实战项目 <a class="header-anchor" href="#模块一实战项目" aria-label="Permalink to “模块一实战项目”">​</a></h3><p><strong>项目名称</strong>：手写 Web 框架实现用户注册登录</p><p><strong>项目内容</strong>：</p><ol><li>设计并实现一个完整的 Web 框架</li><li>设计并实现前缀路由树（通配符、路径参数、正则匹配）</li><li>设计并实现 AOP 方案（logging、tracing、metric、panic 恢复、错误页面）</li><li>设计并实现静态资源服务器（缓存加速、内存控制）</li><li>提供文件上传下载、页面渲染功能</li><li>压测、分析、优化性能（CPU 和内存分配）</li><li>设计并实现 Session 机制</li><li>基于框架实现用户注册、登录服务</li><li>利用 AOP 接口实现用户级限流</li></ol><hr><h2 id="模块二-orm-框架-2周" tabindex="-1">模块二：ORM 框架（2周） <a class="header-anchor" href="#模块二-orm-框架-2周" aria-label="Permalink to “模块二：ORM 框架（2周）”">​</a></h2><h3 id="教学目标-1" tabindex="-1">教学目标 <a class="header-anchor" href="#教学目标-1" aria-label="Permalink to “教学目标”">​</a></h3><ol><li>掌握 ORM 框架的核心设计原理</li><li>掌握数据库连接池的设计与实现</li><li>掌握 SQL 构造器（Query Builder）的设计</li><li>掌握模型映射（Struct 与表映射）机制</li><li>掌握事务管理与嵌套事务实现</li><li>掌握分库分表框架的设计思路</li></ol><h3 id="学习痛点-1" tabindex="-1">学习痛点 <a class="header-anchor" href="#学习痛点-1" aria-label="Permalink to “学习痛点”">​</a></h3><ul><li>只会使用 ORM，不了解 SQL 生成原理</li><li>遇到性能问题时不知道如何优化 ORM 查询</li><li>不了解连接池的工作原理和参数调优</li><li>复杂查询时 ORM 表达能力不足</li></ul><h3 id="第四周-orm-核心设计" tabindex="-1">第四周：ORM 核心设计 <a class="header-anchor" href="#第四周-orm-核心设计" aria-label="Permalink to “第四周：ORM 核心设计”">​</a></h3><h4 id="_4-1-orm-框架概览" tabindex="-1">4.1 ORM 框架概览 <a class="header-anchor" href="#_4-1-orm-框架概览" aria-label="Permalink to “4.1 ORM 框架概览”">​</a></h4><ul><li>ORM 设计哲学：对象关系映射的本质</li><li><strong>开源实例</strong>：GORM、XORM、Ent、Bun 设计对比</li><li>核心组件：Session、Dialect、Query Builder、Executor</li></ul><h4 id="_4-2-数据库连接池" tabindex="-1">4.2 数据库连接池 <a class="header-anchor" href="#_4-2-数据库连接池" aria-label="Permalink to “4.2 数据库连接池”">​</a></h4><ul><li>连接池设计原理</li><li><strong>Go 实现</strong>：<code>database/sql</code> 连接池源码分析</li><li>参数调优：MaxOpenConns、MaxIdleConns、ConnMaxLifetime</li><li><strong>代码演示</strong>：实现自定义连接池</li></ul><h4 id="_4-3-模型定义与元数据解析" tabindex="-1">4.3 模型定义与元数据解析 <a class="header-anchor" href="#_4-3-模型定义与元数据解析" aria-label="Permalink to “4.3 模型定义与元数据解析”">​</a></h4><ul><li>Struct Tag 解析（<code>db:&quot;column_name&quot;</code>）</li><li>反射获取字段类型与标签</li><li>表名、列名映射规则</li><li><strong>代码演示</strong>：实现模型元数据解析器</li></ul><h3 id="第五周-sql-构造与执行" tabindex="-1">第五周：SQL 构造与执行 <a class="header-anchor" href="#第五周-sql-构造与执行" aria-label="Permalink to “第五周：SQL 构造与执行”">​</a></h3><h4 id="_5-1-query-builder-设计" tabindex="-1">5.1 Query Builder 设计 <a class="header-anchor" href="#_5-1-query-builder-设计" aria-label="Permalink to “5.1 Query Builder 设计”">​</a></h4><ul><li>链式调用 API 设计</li><li>条件构造（Where、And、Or）</li><li>聚合查询（Count、Sum、Avg）</li><li>关联查询（Join、Preload）</li><li><strong>代码演示</strong>：实现类型安全的 Query Builder</li></ul><h4 id="_5-2-crud-操作实现" tabindex="-1">5.2 CRUD 操作实现 <a class="header-anchor" href="#_5-2-crud-操作实现" aria-label="Permalink to “5.2 CRUD 操作实现”">​</a></h4><ul><li>Insert：单条/批量插入、Upsert</li><li>Select：单条查询、列表查询、分页</li><li>Update：更新指定字段、乐观锁</li><li>Delete：软删除、物理删除</li><li><strong>代码演示</strong>：实现完整 CRUD 操作</li></ul><h4 id="_5-3-事务管理" tabindex="-1">5.3 事务管理 <a class="header-anchor" href="#_5-3-事务管理" aria-label="Permalink to “5.3 事务管理”">​</a></h4><ul><li>事务 ACID 特性</li><li>事务传播行为</li><li>嵌套事务实现（Savepoint）</li><li><strong>代码演示</strong>：实现事务管理器（支持嵌套事务）</li></ul><h3 id="模块二实战项目" tabindex="-1">模块二实战项目 <a class="header-anchor" href="#模块二实战项目" aria-label="Permalink to “模块二实战项目”">​</a></h3><p><strong>项目名称</strong>：手写 ORM 框架实现博客系统数据层</p><p><strong>项目内容</strong>：</p><ol><li>设计并实现 ORM 核心（Session、Dialect、Query Builder）</li><li>实现模型定义与元数据解析</li><li>实现完整 CRUD 操作（含复杂查询）</li><li>实现事务管理（支持嵌套事务）</li><li>实现连接池管理</li><li>基于 ORM 实现博客系统数据访问层</li><li>性能优化：SQL 日志、慢查询分析</li></ol><hr><h2 id="模块三-缓存系统-2周" tabindex="-1">模块三：缓存系统（2周） <a class="header-anchor" href="#模块三-缓存系统-2周" aria-label="Permalink to “模块三：缓存系统（2周）”">​</a></h2><h3 id="教学目标-2" tabindex="-1">教学目标 <a class="header-anchor" href="#教学目标-2" aria-label="Permalink to “教学目标”">​</a></h3><ol><li>掌握缓存的核心设计原理与策略</li><li>掌握本地缓存（Local Cache）的实现</li><li>掌握 Redis 客户端的设计与实现</li><li>掌握缓存一致性解决方案</li><li>掌握缓存穿透、击穿、雪崩的应对策略</li><li>掌握多级缓存架构设计</li></ol><h3 id="学习痛点-2" tabindex="-1">学习痛点 <a class="header-anchor" href="#学习痛点-2" aria-label="Permalink to “学习痛点”">​</a></h3><ul><li>不了解缓存淘汰策略的实现原理</li><li>缓存与数据库一致性难以保证</li><li>高并发下缓存问题（穿透、击穿、雪崩）频发</li><li>不知道何时用本地缓存、何时用分布式缓存</li></ul><h3 id="第六周-本地缓存与-redis-客户端" tabindex="-1">第六周：本地缓存与 Redis 客户端 <a class="header-anchor" href="#第六周-本地缓存与-redis-客户端" aria-label="Permalink to “第六周：本地缓存与 Redis 客户端”">​</a></h3><h4 id="_6-1-缓存基础与设计原则" tabindex="-1">6.1 缓存基础与设计原则 <a class="header-anchor" href="#_6-1-缓存基础与设计原则" aria-label="Permalink to “6.1 缓存基础与设计原则”">​</a></h4><ul><li>缓存适用场景与成本分析</li><li>缓存设计原则：简单、高效、可控</li><li>缓存淘汰策略：LRU、LFU、FIFO、TTL</li></ul><h4 id="_6-2-本地缓存实现" tabindex="-1">6.2 本地缓存实现 <a class="header-anchor" href="#_6-2-本地缓存实现" aria-label="Permalink to “6.2 本地缓存实现”">​</a></h4><ul><li><strong>开源实例</strong>：BigCache、FreeCache、ristretto 对比</li><li><strong>代码演示</strong>：实现线程安全的 LRU Cache <ul><li>双向链表 + Map 实现 O(1) 操作</li><li>并发安全（分段锁或 sync.Map）</li><li>内存控制与统计</li></ul></li></ul><h4 id="_6-3-redis-协议与客户端设计" tabindex="-1">6.3 Redis 协议与客户端设计 <a class="header-anchor" href="#_6-3-redis-协议与客户端设计" aria-label="Permalink to “6.3 Redis 协议与客户端设计”">​</a></h4><ul><li>Redis 协议（RESP）详解</li><li>连接池设计与实现</li><li>Pipeline 批量操作</li><li>发布订阅模式实现</li><li><strong>代码演示</strong>：实现轻量级 Redis 客户端</li></ul><h3 id="第七周-缓存策略与一致性" tabindex="-1">第七周：缓存策略与一致性 <a class="header-anchor" href="#第七周-缓存策略与一致性" aria-label="Permalink to “第七周：缓存策略与一致性”">​</a></h3><h4 id="_7-1-缓存模式" tabindex="-1">7.1 缓存模式 <a class="header-anchor" href="#_7-1-缓存模式" aria-label="Permalink to “7.1 缓存模式”">​</a></h4><ul><li>Cache-Aside（旁路缓存）</li><li>Read-Through（读穿透）</li><li>Write-Through（写穿透）</li><li>Write-Behind（异步写回）</li></ul><h4 id="_7-2-缓存问题与解决方案" tabindex="-1">7.2 缓存问题与解决方案 <a class="header-anchor" href="#_7-2-缓存问题与解决方案" aria-label="Permalink to “7.2 缓存问题与解决方案”">​</a></h4><ul><li><strong>缓存穿透</strong>：布隆过滤器、空值缓存</li><li><strong>缓存击穿</strong>：互斥锁、逻辑过期</li><li><strong>缓存雪崩</strong>：随机过期时间、多级缓存</li><li><strong>代码演示</strong>：实现缓存防护组件</li></ul><h4 id="_7-3-缓存一致性" tabindex="-1">7.3 缓存一致性 <a class="header-anchor" href="#_7-3-缓存一致性" aria-label="Permalink to “7.3 缓存一致性”">​</a></h4><ul><li>最终一致性 vs 强一致性</li><li>延时双删策略</li><li>消息队列保证一致性</li><li><strong>代码演示</strong>：实现缓存一致性管理器</li></ul><h3 id="模块三实战项目" tabindex="-1">模块三实战项目 <a class="header-anchor" href="#模块三实战项目" aria-label="Permalink to “模块三实战项目”">​</a></h3><p><strong>项目名称</strong>：多级缓存系统实现电商商品详情页</p><p><strong>项目内容</strong>：</p><ol><li>设计并实现本地 LRU Cache</li><li>设计并实现 Redis 客户端（支持 Pipeline）</li><li>实现多级缓存架构（本地 + Redis）</li><li>实现缓存防护（防穿透、击穿、雪崩）</li><li>实现缓存一致性管理</li><li>基于缓存系统实现电商商品详情页</li><li>压测验证缓存效果</li></ol><hr><h2 id="模块四-微服务框架-3周" tabindex="-1">模块四：微服务框架（3周） <a class="header-anchor" href="#模块四-微服务框架-3周" aria-label="Permalink to “模块四：微服务框架（3周）”">​</a></h2><h3 id="教学目标-3" tabindex="-1">教学目标 <a class="header-anchor" href="#教学目标-3" aria-label="Permalink to “教学目标”">​</a></h3><ol><li>掌握微服务架构核心概念与设计原则</li><li>掌握 RPC 框架的设计与实现</li><li>掌握服务注册与发现机制</li><li>掌握负载均衡与熔断降级</li><li>掌握分布式链路追踪</li><li>掌握 gRPC 协议与实现</li></ol><h3 id="学习痛点-3" tabindex="-1">学习痛点 <a class="header-anchor" href="#学习痛点-3" aria-label="Permalink to “学习痛点”">​</a></h3><ul><li>微服务拆分粒度难以把握</li><li>服务间通信性能瓶颈</li><li>服务治理复杂度高（注册发现、限流熔断）</li><li>分布式调试困难</li></ul><h3 id="第八周-rpc-框架设计" tabindex="-1">第八周：RPC 框架设计 <a class="header-anchor" href="#第八周-rpc-框架设计" aria-label="Permalink to “第八周：RPC 框架设计”">​</a></h3><h4 id="_8-1-微服务架构概览" tabindex="-1">8.1 微服务架构概览 <a class="header-anchor" href="#_8-1-微服务架构概览" aria-label="Permalink to “8.1 微服务架构概览”">​</a></h4><ul><li>单体 vs 微服务架构演进</li><li>微服务设计原则与拆分策略</li><li><strong>开源实例</strong>：Go-Kit、Go-Micro、Kratos、Dubbo-go 对比</li></ul><h4 id="_8-2-rpc-核心原理" tabindex="-1">8.2 RPC 核心原理 <a class="header-anchor" href="#_8-2-rpc-核心原理" aria-label="Permalink to “8.2 RPC 核心原理”">​</a></h4><ul><li>RPC 通信模型</li><li>序列化协议：JSON、Protobuf、MsgPack</li><li>网络传输：TCP、HTTP/2、QUIC</li><li><strong>代码演示</strong>：实现简单 RPC 框架</li></ul><h4 id="_8-3-grpc-深度解析" tabindex="-1">8.3 gRPC 深度解析 <a class="header-anchor" href="#_8-3-grpc-深度解析" aria-label="Permalink to “8.3 gRPC 深度解析”">​</a></h4><ul><li>Protocol Buffers 语法与代码生成</li><li>gRPC 四种通信模式</li><li>拦截器（Interceptor）机制</li><li>流控与背压（Backpressure）</li><li><strong>代码演示</strong>：gRPC 服务端与客户端实现</li></ul><h3 id="第九周-服务治理" tabindex="-1">第九周：服务治理 <a class="header-anchor" href="#第九周-服务治理" aria-label="Permalink to “第九周：服务治理”">​</a></h3><h4 id="_9-1-服务注册与发现" tabindex="-1">9.1 服务注册与发现 <a class="header-anchor" href="#_9-1-服务注册与发现" aria-label="Permalink to “9.1 服务注册与发现”">​</a></h4><ul><li>注册中心选型：Consul、Etcd、Nacos、ZooKeeper</li><li>服务注册机制（心跳保活）</li><li>服务发现机制（推拉模式）</li><li><strong>代码演示</strong>：实现服务注册发现客户端</li></ul><h4 id="_9-2-负载均衡" tabindex="-1">9.2 负载均衡 <a class="header-anchor" href="#_9-2-负载均衡" aria-label="Permalink to “9.2 负载均衡”">​</a></h4><ul><li>负载均衡算法：轮询、随机、加权、一致性哈希</li><li>健康检查机制</li><li><strong>代码演示</strong>：实现客户端负载均衡器</li></ul><h4 id="_9-3-熔断与降级" tabindex="-1">9.3 熔断与降级 <a class="header-anchor" href="#_9-3-熔断与降级" aria-label="Permalink to “9.3 熔断与降级”">​</a></h4><ul><li>熔断器模式（Circuit Breaker）</li><li>熔断状态机：Closed、Open、Half-Open</li><li>降级策略实现</li><li><strong>开源实例</strong>：Hystrix、Sentinel 原理</li><li><strong>代码演示</strong>：实现熔断降级组件</li></ul><h3 id="第十周-可观测性" tabindex="-1">第十周：可观测性 <a class="header-anchor" href="#第十周-可观测性" aria-label="Permalink to “第十周：可观测性”">​</a></h3><h4 id="_10-1-分布式链路追踪" tabindex="-1">10.1 分布式链路追踪 <a class="header-anchor" href="#_10-1-分布式链路追踪" aria-label="Permalink to “10.1 分布式链路追踪”">​</a></h4><ul><li>链路追踪核心概念：Trace、Span、Baggage</li><li>OpenTelemetry 标准</li><li>采样策略与性能优化</li><li><strong>代码演示</strong>：实现分布式链路追踪中间件</li></ul><h4 id="_10-2-指标监控" tabindex="-1">10.2 指标监控 <a class="header-anchor" href="#_10-2-指标监控" aria-label="Permalink to “10.2 指标监控”">​</a></h4><ul><li>Metrics 类型：Counter、Gauge、Histogram、Summary</li><li>Prometheus 集成</li><li><strong>代码演示</strong>：实现指标收集与上报</li></ul><h4 id="_10-3-日志聚合" tabindex="-1">10.3 日志聚合 <a class="header-anchor" href="#_10-3-日志聚合" aria-label="Permalink to “10.3 日志聚合”">​</a></h4><ul><li>结构化日志设计</li><li>日志收集与聚合方案</li><li>ELK/Loki 集成</li></ul><h3 id="模块四实战项目" tabindex="-1">模块四实战项目 <a class="header-anchor" href="#模块四实战项目" aria-label="Permalink to “模块四实战项目”">​</a></h3><p><strong>项目名称</strong>：微服务框架实现订单系统</p><p><strong>项目内容</strong>：</p><ol><li>设计并实现 RPC 框架（支持 Protobuf）</li><li>实现服务注册与发现（基于 Etcd）</li><li>实现客户端负载均衡</li><li>实现熔断降级组件</li><li>实现分布式链路追踪</li><li>实现指标监控与日志聚合</li><li>基于微服务框架实现订单系统（用户服务、商品服务、订单服务）</li></ol><hr><h2 id="模块五-分布式事务-2周" tabindex="-1">模块五：分布式事务（2周） <a class="header-anchor" href="#模块五-分布式事务-2周" aria-label="Permalink to “模块五：分布式事务（2周）”">​</a></h2><h3 id="教学目标-4" tabindex="-1">教学目标 <a class="header-anchor" href="#教学目标-4" aria-label="Permalink to “教学目标”">​</a></h3><ol><li>掌握分布式事务核心概念与理论基础</li><li>掌握 2PC、3PC、TCC、Saga 等事务模式</li><li>掌握 Seata 分布式事务框架原理</li><li>掌握本地消息表实现最终一致性</li><li>掌握事务消息（RocketMQ）实现</li></ol><h3 id="学习痛点-4" tabindex="-1">学习痛点 <a class="header-anchor" href="#学习痛点-4" aria-label="Permalink to “学习痛点”">​</a></h3><ul><li>分布式事务方案选择困难</li><li>2PC 性能瓶颈与单点故障</li><li>TCC 业务侵入性高</li><li>最终一致性难以验证</li></ul><h3 id="第十一周-分布式事务理论" tabindex="-1">第十一周：分布式事务理论 <a class="header-anchor" href="#第十一周-分布式事务理论" aria-label="Permalink to “第十一周：分布式事务理论”">​</a></h3><h4 id="_11-1-分布式事务基础" tabindex="-1">11.1 分布式事务基础 <a class="header-anchor" href="#_11-1-分布式事务基础" aria-label="Permalink to “11.1 分布式事务基础”">​</a></h4><ul><li>ACID vs BASE 理论</li><li>CAP 定理与权衡</li><li>分布式事务分类：刚性事务 vs 柔性事务</li></ul><h4 id="_11-2-分布式事务协议" tabindex="-1">11.2 分布式事务协议 <a class="header-anchor" href="#_11-2-分布式事务协议" aria-label="Permalink to “11.2 分布式事务协议”">​</a></h4><ul><li><strong>2PC（两阶段提交）</strong>：原理、优缺点、实现</li><li><strong>3PC（三阶段提交）</strong>：改进与局限</li><li><strong>TCC（Try-Confirm-Cancel）</strong>：设计要点与幂等性</li><li><strong>Saga 模式</strong>：编排式 vs 协调式</li><li><strong>开源实例</strong>：Seata 架构与实现原理</li></ul><h3 id="第十二周-分布式事务实践" tabindex="-1">第十二周：分布式事务实践 <a class="header-anchor" href="#第十二周-分布式事务实践" aria-label="Permalink to “第十二周：分布式事务实践”">​</a></h3><h4 id="_12-1-本地消息表方案" tabindex="-1">12.1 本地消息表方案 <a class="header-anchor" href="#_12-1-本地消息表方案" aria-label="Permalink to “12.1 本地消息表方案”">​</a></h4><ul><li>方案设计与实现步骤</li><li>消息投递与消费幂等性</li><li>定时任务补偿机制</li><li><strong>代码演示</strong>：实现本地消息表分布式事务</li></ul><h4 id="_12-2-事务消息方案" tabindex="-1">12.2 事务消息方案 <a class="header-anchor" href="#_12-2-事务消息方案" aria-label="Permalink to “12.2 事务消息方案”">​</a></h4><ul><li>RocketMQ 事务消息原理</li><li>半消息与回查机制</li><li><strong>代码演示</strong>：基于 RocketMQ 实现分布式事务</li></ul><h4 id="_12-3-分布式事务框架设计" tabindex="-1">12.3 分布式事务框架设计 <a class="header-anchor" href="#_12-3-分布式事务框架设计" aria-label="Permalink to “12.3 分布式事务框架设计”">​</a></h4><ul><li>事务协调器设计</li><li>事务日志存储</li><li>超时与回滚机制</li><li><strong>代码演示</strong>：实现简化版分布式事务框架</li></ul><h3 id="模块五实战项目" tabindex="-1">模块五实战项目 <a class="header-anchor" href="#模块五实战项目" aria-label="Permalink to “模块五实战项目”">​</a></h3><p><strong>项目名称</strong>：分布式事务实现电商下单扣库存</p><p><strong>项目内容</strong>：</p><ol><li>实现 TCC 模式分布式事务</li><li>实现 Saga 模式分布式事务</li><li>实现本地消息表方案</li><li>基于 RocketMQ 实现事务消息</li><li>设计并实现简化版事务协调器</li><li>完整实现电商下单扣库存场景（订单创建、库存扣减、账户扣款）</li></ol><hr><h2 id="模块六-消息队列-2周" tabindex="-1">模块六：消息队列（2周） <a class="header-anchor" href="#模块六-消息队列-2周" aria-label="Permalink to “模块六：消息队列（2周）”">​</a></h2><h3 id="教学目标-5" tabindex="-1">教学目标 <a class="header-anchor" href="#教学目标-5" aria-label="Permalink to “教学目标”">​</a></h3><ol><li>掌握消息队列核心概念与应用场景</li><li>掌握 Kafka 架构原理与使用</li><li>掌握 RocketMQ 架构原理与使用</li><li>掌握消息队列设计与实现</li><li>掌握消息可靠性保证机制</li></ol><h3 id="学习痛点-5" tabindex="-1">学习痛点 <a class="header-anchor" href="#学习痛点-5" aria-label="Permalink to “学习痛点”">​</a></h3><ul><li>消息丢失、重复消费问题频发</li><li>消息顺序性难以保证</li><li>消息积压处理困难</li><li>消息队列选型困难</li></ul><h3 id="第十三周-消息队列原理与-kafka" tabindex="-1">第十三周：消息队列原理与 Kafka <a class="header-anchor" href="#第十三周-消息队列原理与-kafka" aria-label="Permalink to “第十三周：消息队列原理与 Kafka”">​</a></h3><h4 id="_13-1-消息队列基础" tabindex="-1">13.1 消息队列基础 <a class="header-anchor" href="#_13-1-消息队列基础" aria-label="Permalink to “13.1 消息队列基础”">​</a></h4><ul><li>消息队列核心概念：Topic、Partition、Consumer Group</li><li>消息队列应用场景：异步解耦、流量削峰、数据同步</li><li><strong>开源产品</strong>：Kafka、RocketMQ、RabbitMQ、Pulsar 对比</li></ul><h4 id="_13-2-kafka-深度解析" tabindex="-1">13.2 Kafka 深度解析 <a class="header-anchor" href="#_13-2-kafka-深度解析" aria-label="Permalink to “13.2 Kafka 深度解析”">​</a></h4><ul><li>Kafka 架构：Producer、Broker、Consumer、ZooKeeper/KRaft</li><li>存储机制：日志段、索引、零拷贝</li><li>副本机制：ISR、Leader 选举</li><li>消费者组与分区分配策略</li><li><strong>代码演示</strong>：Kafka Producer 与 Consumer 实现</li></ul><h3 id="第十四周-rocketmq-与消息队列设计" tabindex="-1">第十四周：RocketMQ 与消息队列设计 <a class="header-anchor" href="#第十四周-rocketmq-与消息队列设计" aria-label="Permalink to “第十四周：RocketMQ 与消息队列设计”">​</a></h3><h4 id="_14-1-rocketmq-深度解析" tabindex="-1">14.1 RocketMQ 深度解析 <a class="header-anchor" href="#_14-1-rocketmq-深度解析" aria-label="Permalink to “14.1 RocketMQ 深度解析”">​</a></h4><ul><li>RocketMQ 架构：NameServer、Broker、Producer、Consumer</li><li>消息存储：CommitLog、ConsumeQueue、IndexFile</li><li>消息类型：普通消息、顺序消息、延时消息、事务消息</li><li><strong>代码演示</strong>：RocketMQ 各类消息实现</li></ul><h4 id="_14-2-消息可靠性保证" tabindex="-1">14.2 消息可靠性保证 <a class="header-anchor" href="#_14-2-消息可靠性保证" aria-label="Permalink to “14.2 消息可靠性保证”">​</a></h4><ul><li>消息不丢失：生产者确认、Broker 持久化、消费者确认</li><li>消息不重复：幂等性设计</li><li>消息顺序性：分区顺序、全局顺序</li><li><strong>代码演示</strong>：实现可靠消息投递组件</li></ul><h4 id="_14-3-消息队列设计实现" tabindex="-1">14.3 消息队列设计实现 <a class="header-anchor" href="#_14-3-消息队列设计实现" aria-label="Permalink to “14.3 消息队列设计实现”">​</a></h4><ul><li>存储引擎设计（基于文件或 LSM Tree）</li><li>网络通信层设计</li><li>消费进度管理</li><li><strong>代码演示</strong>：实现简化版消息队列</li></ul><h3 id="模块六实战项目" tabindex="-1">模块六实战项目 <a class="header-anchor" href="#模块六实战项目" aria-label="Permalink to “模块六实战项目”">​</a></h3><p><strong>项目名称</strong>：消息队列实现秒杀系统</p><p><strong>项目内容</strong>：</p><ol><li>基于 Kafka 实现日志收集系统</li><li>基于 RocketMQ 实现订单异步处理</li><li>实现可靠消息投递组件</li><li>实现消息顺序消费</li><li>实现延时消息处理</li><li>基于消息队列实现秒杀系统（流量削峰、异步下单）</li></ol><hr><h2 id="模块七-日志与监控-1周" tabindex="-1">模块七：日志与监控（1周） <a class="header-anchor" href="#模块七-日志与监控-1周" aria-label="Permalink to “模块七：日志与监控（1周）”">​</a></h2><h3 id="教学目标-6" tabindex="-1">教学目标 <a class="header-anchor" href="#教学目标-6" aria-label="Permalink to “教学目标”">​</a></h3><ol><li>掌握日志系统设计原则与最佳实践</li><li>掌握 zap、logrus 等日志库原理与使用</li><li>掌握日志收集与聚合方案</li><li>掌握系统监控指标设计与采集</li><li>掌握告警机制设计</li></ol><h3 id="学习痛点-6" tabindex="-1">学习痛点 <a class="header-anchor" href="#学习痛点-6" aria-label="Permalink to “学习痛点”">​</a></h3><ul><li>日志打印不规范，难以排查问题</li><li>日志性能影响系统吞吐量</li><li>监控指标设计不合理，告警泛滥</li><li>缺乏统一的日志与监控体系</li></ul><h3 id="第十五周-日志与监控体系" tabindex="-1">第十五周：日志与监控体系 <a class="header-anchor" href="#第十五周-日志与监控体系" aria-label="Permalink to “第十五周：日志与监控体系”">​</a></h3><h4 id="_15-1-日志系统设计" tabindex="-1">15.1 日志系统设计 <a class="header-anchor" href="#_15-1-日志系统设计" aria-label="Permalink to “15.1 日志系统设计”">​</a></h4><ul><li>日志级别与规范</li><li>结构化日志设计（JSON 格式）</li><li><strong>开源库</strong>：zap、logrus、zerolog 对比与原理</li><li>日志分割与归档</li><li><strong>代码演示</strong>：实现高性能日志库</li></ul><h4 id="_15-2-日志收集与聚合" tabindex="-1">15.2 日志收集与聚合 <a class="header-anchor" href="#_15-2-日志收集与聚合" aria-label="Permalink to “15.2 日志收集与聚合”">​</a></h4><ul><li>日志收集方案：Filebeat、Fluentd、Vector</li><li>日志存储：Elasticsearch、Loki、ClickHouse</li><li>日志查询与分析</li><li><strong>代码演示</strong>：集成 ELK 日志体系</li></ul><h4 id="_15-3-系统监控设计" tabindex="-1">15.3 系统监控设计 <a class="header-anchor" href="#_15-3-系统监控设计" aria-label="Permalink to “15.3 系统监控设计”">​</a></h4><ul><li>监控指标设计：RED 方法、USE 方法</li><li><strong>开源方案</strong>：Prometheus + Grafana</li><li>自定义指标采集</li><li><strong>代码演示</strong>：实现应用指标采集器</li></ul><h4 id="_15-4-告警机制" tabindex="-1">15.4 告警机制 <a class="header-anchor" href="#_15-4-告警机制" aria-label="Permalink to “15.4 告警机制”">​</a></h4><ul><li>告警分级与收敛</li><li>告警渠道：邮件、短信、钉钉、企业微信</li><li><strong>代码演示</strong>：实现告警管理器</li></ul><h3 id="模块七实战项目" tabindex="-1">模块七实战项目 <a class="header-anchor" href="#模块七实战项目" aria-label="Permalink to “模块七实战项目”">​</a></h3><p><strong>项目名称</strong>：日志监控体系实现全链路可观测</p><p><strong>项目内容</strong>：</p><ol><li>设计并实现高性能日志库</li><li>集成 ELK 实现日志收集与查询</li><li>设计并实现应用指标采集器</li><li>集成 Prometheus + Grafana</li><li>实现告警管理器</li><li>构建完整的日志监控体系</li></ol><hr><h2 id="模块八-工程化与最佳实践-1周" tabindex="-1">模块八：工程化与最佳实践（1周） <a class="header-anchor" href="#模块八-工程化与最佳实践-1周" aria-label="Permalink to “模块八：工程化与最佳实践（1周）”">​</a></h2><h3 id="教学目标-7" tabindex="-1">教学目标 <a class="header-anchor" href="#教学目标-7" aria-label="Permalink to “教学目标”">​</a></h3><ol><li>掌握 Go 项目工程化规范</li><li>掌握单元测试、集成测试、压测方法</li><li>掌握性能调优技巧与工具</li><li>掌握 CI/CD 流程设计</li><li>掌握代码审查与重构方法</li></ol><h3 id="学习痛点-7" tabindex="-1">学习痛点 <a class="header-anchor" href="#学习痛点-7" aria-label="Permalink to “学习痛点”">​</a></h3><ul><li>项目结构混乱，代码难以维护</li><li>测试覆盖率低，上线频繁出问题</li><li>性能瓶颈难以定位</li><li>缺乏系统化的工程化实践</li></ul><h3 id="第十六周-工程化实践" tabindex="-1">第十六周：工程化实践 <a class="header-anchor" href="#第十六周-工程化实践" aria-label="Permalink to “第十六周：工程化实践”">​</a></h3><h4 id="_16-1-项目工程化规范" tabindex="-1">16.1 项目工程化规范 <a class="header-anchor" href="#_16-1-项目工程化规范" aria-label="Permalink to “16.1 项目工程化规范”">​</a></h4><ul><li>项目目录结构设计（Standard Go Project Layout）</li><li>代码规范：gofmt、golint、go vet</li><li>接口设计与版本管理</li><li>错误处理最佳实践</li><li><strong>代码演示</strong>：构建标准 Go 项目模板</li></ul><h4 id="_16-2-测试体系" tabindex="-1">16.2 测试体系 <a class="header-anchor" href="#_16-2-测试体系" aria-label="Permalink to “16.2 测试体系”">​</a></h4><ul><li>单元测试：testing 包、 testify 框架</li><li>测试覆盖率：go test -cover</li><li>Mock 测试：gomock、mockery</li><li>集成测试与端到端测试</li><li>压测工具：wrk、vegeta、go-wrk</li><li><strong>代码演示</strong>：实现完整测试套件</li></ul><h4 id="_16-3-性能调优" tabindex="-1">16.3 性能调优 <a class="header-anchor" href="#_16-3-性能调优" aria-label="Permalink to “16.3 性能调优”">​</a></h4><ul><li>性能分析工具：pprof、trace</li><li>CPU 优化：减少内存分配、避免反射</li><li>内存优化：对象池、逃逸分析</li><li>并发优化：GMP 调度、Channel 优化</li><li><strong>代码演示</strong>：性能分析与优化实战</li></ul><h4 id="_16-4-ci-cd-与-devops" tabindex="-1">16.4 CI/CD 与 DevOps <a class="header-anchor" href="#_16-4-ci-cd-与-devops" aria-label="Permalink to “16.4 CI/CD 与 DevOps”">​</a></h4><ul><li>Git 工作流：Git Flow、GitHub Flow</li><li>CI/CD 工具：GitHub Actions、GitLab CI、Jenkins</li><li>自动化测试与部署</li><li>容器化：Docker、Kubernetes</li><li><strong>代码演示</strong>：构建完整 CI/CD 流水线</li></ul><h3 id="模块八实战项目" tabindex="-1">模块八实战项目 <a class="header-anchor" href="#模块八实战项目" aria-label="Permalink to “模块八实战项目”">​</a></h3><p><strong>项目名称</strong>：工程化实践构建生产级应用</p><p><strong>项目内容</strong>：</p><ol><li>设计标准 Go 项目结构</li><li>实现完整单元测试与集成测试（覆盖率 &gt; 80%）</li><li>性能分析与优化（CPU、内存、并发）</li><li>构建 Docker 镜像与 Kubernetes 部署</li><li>搭建 CI/CD 流水线</li><li>代码审查与重构</li></ol><hr><h2 id="加餐-热门面试主题-穿插进行" tabindex="-1">加餐：热门面试主题（穿插进行） <a class="header-anchor" href="#加餐-热门面试主题-穿插进行" aria-label="Permalink to “加餐：热门面试主题（穿插进行）”">​</a></h2><h3 id="主题一-并发等待队列实现" tabindex="-1">主题一：并发等待队列实现 <a class="header-anchor" href="#主题一-并发等待队列实现" aria-label="Permalink to “主题一：并发等待队列实现”">​</a></h3><ul><li>有界队列 vs 无界队列</li><li>阻塞队列实现（Channel、Condition）</li><li>优先级队列设计</li><li><strong>代码演示</strong>：实现高并发等待队列</li></ul><h3 id="主题二-sso-oauth2-系统设计" tabindex="-1">主题二：SSO/OAuth2 系统设计 <a class="header-anchor" href="#主题二-sso-oauth2-系统设计" aria-label="Permalink to “主题二：SSO/OAuth2 系统设计”">​</a></h3><ul><li>单点登录原理</li><li>OAuth2 授权流程</li><li>JWT 设计与实现</li><li><strong>代码演示</strong>：实现 SSO 认证中心</li></ul><h3 id="主题三-增强-orm-框架" tabindex="-1">主题三：增强 ORM 框架 <a class="header-anchor" href="#主题三-增强-orm-框架" aria-label="Permalink to “主题三：增强 ORM 框架”">​</a></h3><ul><li>分库分表设计</li><li>读写分离实现</li><li>慢查询分析与优化</li><li><strong>代码演示</strong>：实现分库分表组件</li></ul><h3 id="主题四-全链路压测" tabindex="-1">主题四：全链路压测 <a class="header-anchor" href="#主题四-全链路压测" aria-label="Permalink to “主题四：全链路压测”">​</a></h3><ul><li>压测方案设计</li><li>流量录制与回放</li><li>影子库与数据隔离</li><li><strong>代码演示</strong>：实现压测平台</li></ul><hr><h2 id="四大实战案例汇总" tabindex="-1">四大实战案例汇总 <a class="header-anchor" href="#四大实战案例汇总" aria-label="Permalink to “四大实战案例汇总”">​</a></h2><h3 id="案例一-手写-web-框架实现用户注册登录" tabindex="-1">案例一：手写 Web 框架实现用户注册登录 <a class="header-anchor" href="#案例一-手写-web-框架实现用户注册登录" aria-label="Permalink to “案例一：手写 Web 框架实现用户注册登录”">​</a></h3><ul><li><strong>关联模块</strong>：模块一</li><li><strong>核心技能</strong>：路由树、AOP、Session、静态资源</li></ul><h3 id="案例二-多级缓存系统实现电商商品详情页" tabindex="-1">案例二：多级缓存系统实现电商商品详情页 <a class="header-anchor" href="#案例二-多级缓存系统实现电商商品详情页" aria-label="Permalink to “案例二：多级缓存系统实现电商商品详情页”">​</a></h3><ul><li><strong>关联模块</strong>：模块三</li><li><strong>核心技能</strong>：本地缓存、Redis、缓存一致性、缓存防护</li></ul><h3 id="案例三-微服务框架实现订单系统" tabindex="-1">案例三：微服务框架实现订单系统 <a class="header-anchor" href="#案例三-微服务框架实现订单系统" aria-label="Permalink to “案例三：微服务框架实现订单系统”">​</a></h3><ul><li><strong>关联模块</strong>：模块四</li><li><strong>核心技能</strong>：RPC、服务治理、熔断降级、链路追踪</li></ul><h3 id="案例四-分布式事务实现电商下单扣库存" tabindex="-1">案例四：分布式事务实现电商下单扣库存 <a class="header-anchor" href="#案例四-分布式事务实现电商下单扣库存" aria-label="Permalink to “案例四：分布式事务实现电商下单扣库存”">​</a></h3><ul><li><strong>关联模块</strong>：模块五</li><li><strong>核心技能</strong>：TCC、Saga、事务消息、最终一致性</li></ul><hr><h2 id="学习路径建议" tabindex="-1">学习路径建议 <a class="header-anchor" href="#学习路径建议" aria-label="Permalink to “学习路径建议”">​</a></h2><h3 id="阶段一-基础夯实-第-1-3-周" tabindex="-1">阶段一：基础夯实（第 1-3 周） <a class="header-anchor" href="#阶段一-基础夯实-第-1-3-周" aria-label="Permalink to “阶段一：基础夯实（第 1-3 周）”">​</a></h3><ul><li>完成模块一：Web 框架</li><li>理解 HTTP 原理与 Web 框架设计</li><li>完成案例一</li></ul><h3 id="阶段二-数据层能力-第-4-5-周" tabindex="-1">阶段二：数据层能力（第 4-5 周） <a class="header-anchor" href="#阶段二-数据层能力-第-4-5-周" aria-label="Permalink to “阶段二：数据层能力（第 4-5 周）”">​</a></h3><ul><li>完成模块二：ORM 框架</li><li>掌握数据库交互核心原理</li></ul><h3 id="阶段三-性能优化-第-6-7-周" tabindex="-1">阶段三：性能优化（第 6-7 周） <a class="header-anchor" href="#阶段三-性能优化-第-6-7-周" aria-label="Permalink to “阶段三：性能优化（第 6-7 周）”">​</a></h3><ul><li>完成模块三：缓存系统</li><li>掌握高并发系统性能优化</li><li>完成案例二</li></ul><h3 id="阶段四-分布式架构-第-8-12-周" tabindex="-1">阶段四：分布式架构（第 8-12 周） <a class="header-anchor" href="#阶段四-分布式架构-第-8-12-周" aria-label="Permalink to “阶段四：分布式架构（第 8-12 周）”">​</a></h3><ul><li>完成模块四：微服务框架</li><li>完成模块五：分布式事务</li><li>完成模块六：消息队列</li><li>完成案例三、案例四</li></ul><h3 id="阶段五-工程化落地-第-13-16-周" tabindex="-1">阶段五：工程化落地（第 13-16 周） <a class="header-anchor" href="#阶段五-工程化落地-第-13-16-周" aria-label="Permalink to “阶段五：工程化落地（第 13-16 周）”">​</a></h3><ul><li>完成模块七：日志与监控</li><li>完成模块八：工程化与最佳实践</li><li>整合所有知识，构建生产级应用</li></ul><hr><h2 id="技术栈全景" tabindex="-1">技术栈全景 <a class="header-anchor" href="#技术栈全景" aria-label="Permalink to “技术栈全景”">​</a></h2><h3 id="核心语言与标准库" tabindex="-1">核心语言与标准库 <a class="header-anchor" href="#核心语言与标准库" aria-label="Permalink to “核心语言与标准库”">​</a></h3><ul><li>Go 1.21+</li><li><code>net/http</code>、<code>database/sql</code>、<code>context</code>、<code>sync</code></li></ul><h3 id="主流开源框架" tabindex="-1">主流开源框架 <a class="header-anchor" href="#主流开源框架" aria-label="Permalink to “主流开源框架”">​</a></h3><ul><li><strong>Web</strong>：Gin、Beego、Echo、Fiber</li><li><strong>ORM</strong>：GORM、Ent、Bun</li><li><strong>缓存</strong>：Redis、BigCache、ristretto</li><li><strong>RPC</strong>：gRPC、Dubbo-go、Kratos</li><li><strong>消息队列</strong>：Kafka、RocketMQ</li><li><strong>注册中心</strong>：Consul、Etcd、Nacos</li></ul><h3 id="基础设施" tabindex="-1">基础设施 <a class="header-anchor" href="#基础设施" aria-label="Permalink to “基础设施”">​</a></h3><ul><li><strong>数据库</strong>：MySQL、PostgreSQL</li><li><strong>缓存</strong>：Redis、Memcached</li><li><strong>容器</strong>：Docker、Kubernetes</li><li><strong>监控</strong>：Prometheus、Grafana、ELK</li><li><strong>CI/CD</strong>：GitHub Actions、GitLab CI</li></ul><hr><h2 id="面试要点汇总" tabindex="-1">面试要点汇总 <a class="header-anchor" href="#面试要点汇总" aria-label="Permalink to “面试要点汇总”">​</a></h2><h3 id="高频面试题" tabindex="-1">高频面试题 <a class="header-anchor" href="#高频面试题" aria-label="Permalink to “高频面试题”">​</a></h3><ol><li><strong>Web 框架</strong>：前缀路由树原理、AOP 实现、中间件执行顺序</li><li><strong>ORM</strong>：SQL 生成原理、连接池参数调优、事务隔离级别</li><li><strong>缓存</strong>：缓存一致性、穿透/击穿/雪崩解决方案、Redis 数据类型</li><li><strong>微服务</strong>：RPC 原理、服务注册发现、熔断降级、链路追踪</li><li><strong>分布式事务</strong>：2PC/TCC/Saga 对比、最终一致性保证</li><li><strong>消息队列</strong>：Kafka/RocketMQ 架构、消息可靠性、顺序消费</li><li><strong>性能优化</strong>：pprof 使用、内存分配优化、GMP 调度</li></ol><h3 id="源码阅读清单" tabindex="-1">源码阅读清单 <a class="header-anchor" href="#源码阅读清单" aria-label="Permalink to “源码阅读清单”">​</a></h3><ul><li><code>net/http</code> 标准库</li><li><code>database/sql</code> 连接池</li><li>Gin 路由树实现</li><li>GORM 核心实现</li><li>etcd Raft 算法</li><li>Kafka 存储机制</li></ul><hr><h2 id="附录" tabindex="-1">附录 <a class="header-anchor" href="#附录" aria-label="Permalink to “附录”">​</a></h2><h3 id="推荐学习资源" tabindex="-1">推荐学习资源 <a class="header-anchor" href="#推荐学习资源" aria-label="Permalink to “推荐学习资源”">​</a></h3><ul><li>《Go 程序设计语言》</li><li>《Go 语言高级编程》</li><li>Go 官方博客与文档</li><li>极客时间《Go 语言从入门到实战》</li></ul><h3 id="实践项目建议" tabindex="-1">实践项目建议 <a class="header-anchor" href="#实践项目建议" aria-label="Permalink to “实践项目建议”">​</a></h3><ul><li>个人博客系统（Web + ORM）</li><li>短链接服务（缓存 + 分布式 ID）</li><li>即时通讯系统（WebSocket + 消息队列）</li><li>微服务电商平台（全栈实践）</li></ul>',254)])])}const u=i(o,[["render",n]]);export{g as __pageData,u as default};
